"""Тесты провайдеров: контракт title/description, PdfExtractProvider."""from __future__ import annotationsfrom pathlib import Pathimport pytestfrom src.modules.file_extract.services.file_extract_cache import FileExtractCacheServicefrom src.modules.file_extract.models import (    CONTENT_TYPE_IMAGE,    ExtractConfig,    SourceDocument,    compute_extract_hash,)from src.modules.file_extract.providers import PdfExtractProviderdef test_provider_contract_title_and_description() -> None:    """Провайдер реализует provider_title() и provider_description(); описание группы может быть пустым (детали в полях схемы)."""    assert PdfExtractProvider.provider_title() == "Обработка PDF"    assert isinstance(PdfExtractProvider.provider_description(), str)def test_pdf_extract_provider_supported_extensions():    assert PdfExtractProvider.supported_extensions() == {".pdf"}def test_pdf_extract_provider_extract_returns_page_images(tmp_path: Path):    try:        import fitz    except ImportError:        pytest.skip("PyMuPDF not installed")    provider = PdfExtractProvider()    config = ExtractConfig(        project_path=tmp_path,        provider_configs={            PdfExtractProvider.provider_code(): {                "algorithm": PdfExtractProvider.PDF_EXTRACT_MODE_IMAGES_ALWAYS,                "render_scale": "2",            }        },    )    doc_hash = compute_extract_hash(config, "h1")    storage = FileExtractCacheService(config, doc_hash)    pdf_path = tmp_path / "doc.pdf"    doc = fitz.open()    doc.new_page()    doc.new_page()    doc.save(pdf_path)    doc.close()    source = SourceDocument(        path=str(pdf_path),        folder=".",        filename="doc.pdf",        extension=".pdf",        mime_type="application/pdf",        file_hash="h1",    )    result = provider.extract(source, config, storage, document_hash=doc_hash)    assert result.source.path == source.path    assert result.config is config    assert result.extract_hash == doc_hash    assert len(result.content) == 2    assert all(item.content_type == CONTENT_TYPE_IMAGE for item in result.content)    assert all(item.path_obj() and item.path_obj().suffix.lower() == ".jpg" for item in result.content)